    var _litOn = !dormant && !(S.profile && S.profile.simpleMode) && !!(S.profile && S.profile.set);
    var _litOpenDone = _litOn && ((S.tools || {}).gauge || []).some(function (g) { return g.k === k && (g.stack === "daily-stack" || g.stack === "first-stack"); });
