    if (stage <= 0) { gctx.fillStyle = "#3f8a5e"; gctx.beginPath(); gctx.ellipse(xx, yy - 1, 5, 2.4, 0, 0, 7); gctx.fill(); return; } // seed-mound
    if (stage === 1) { gctx.fillStyle = "#2f6b4a"; gctx.fillRect(xx - 1, yy - 5, 2, 5); gctx.fillStyle = "#3f8a5e"; gctx.fillRect(xx - 3, yy - 5, 3, 2); return; } // sprout
    gctx.fillStyle = "#2f6b4a"; gctx.fillRect(xx - 1, yy - 12, 3, 12);
