    var g = (S.game.garden || []).slice(-5), N = g.length, baseY = 62;
    var xs = []; for (var i = 0; i < N; i++) xs.push(22 + (i * (56 / Math.max(1, (N - 1) || 1)))); if (N === 1) xs = [50];
