  var TT_POOL = [["early", "Woke early", "ti-sunrise", "Wake early", "upkeep"], ["moved", "Moved my body", "ti-run", "Move my body", "move"], ["deep", "Did real work", "ti-target", "One focus block", "focus"], ["people", "Saw good people", "ti-users", "Reach one good person", "connect"], ["outside", "Got outside", "ti-tree", "Ten minutes outside", "move"], ["quiet", "Quiet time", "ti-wind", "Ten quiet minutes", "restore"], ["create", "Made something", "ti-palette", "Make something small", "create"], ["scroll", "Scrolled a lot", "ti-device-mobile", "", ""], ["late", "Slept in / late", "ti-alarm-snooze", "", ""], ["skip", "Skipped meals", "ti-bowl", "One real meal", "nourish"]];
